import { describe, test, expect, vi, beforeEach } from "vitest";
import request from "supertest";
import { app } from "../app.js";

vi.mock("../db.js", () => ({ query: vi.fn() }));

// The auth middleware is mocked so we can control authentication in each test
// without needing real sessions or tokens. We keep a reference to the inner
// function so we can swap its behavior per-test with mockImplementation.
const mockRequireAuth = vi.fn();
vi.mock("../middleware/auth.js", () => ({
  requireAuth: (req, res, next) => mockRequireAuth(req, res, next),
}));

import { query } from "../db.js";

// Helpers that configure the auth mock for the two common cases.
// Calling these at the top of a test makes its authentication state explicit.
const asUser = (user = { id: 1, username: "alice" }) => {
  mockRequireAuth.mockImplementation((req, res, next) => {
    req.user = user;
    next();
  });
};

const asGuest = () => {
  mockRequireAuth.mockImplementation((req, res) => {
    res.status(401).json({ message: "Unauthorized" });
  });
