import { describe, test, expect, vi, beforeEach } from "vitest";
import request from "supertest";
import { app } from "../app.js";

// vi.mock() is hoisted to the top of the file by Vitest's transformer,
// so even though these calls appear after the imports in source, they run
// before any module is evaluated. The imported `query` and `bcrypt` below
// will already be the mocked versions when the tests run.
vi.mock("../db.js", () => ({ query: vi.fn() }));
vi.mock("bcrypt", () => ({
  default: {
    hash: vi.fn().mockResolvedValue("$2b$10$hashed_password"),
    compare: vi.fn(),
  },
}));

import { query } from "../db.js";
import bcrypt from "bcrypt";

describe("POST /api/auth/register", () => {
  // clearAllMocks resets call counts and return values before each test,
  // so one test's mock setup doesn't bleed into the next.
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test("returns 400 when username is empty", () => {
    return request(app)
      .post("/api/auth/register")
      .send({ username: "", password: "secure123" })
      .expect(400)
      .expect((res) => {
        expect(res.body.message).toMatch(/username/i);
      });
  });

  test("returns 400 when password is shorter than 8 characters", () => {
    return request(app)
      .post("/api/auth/register")
      .send({ username: "alice", password: "short" })
      .expect(400)
      .expect((res) => {
        expect(res.body.message).toMatch(/password/i);
      });
  });

  test("returns 409 when username is already taken", () => {
    // mockResolvedValueOnce — only applies to the next call, then resets.
    // This lets you chain different responses for different queries in one test.
    vi.mocked(query).mockResolvedValueOnce({ rows: [{ id: 42 }] }); // user exists

    return request(app)
      .post("/api/auth/register")
      .send({ username: "alice", password: "secure123" })
      .expect(409)
      .expect((res) => {
        expect(res.body.message).toMatch(/taken|already exists/i);
      });
  });

  test("creates user and returns 201 on valid input", () => {
    vi.mocked(query)
      .mockResolvedValueOnce({ rows: [] }) // username not taken
      .mockResolvedValueOnce({ rows: [{ id: 1, username: "alice" }] }); // INSERT result

    return request(app)
      .post("/api/auth/register")
      .send({ username: "alice", password: "secure123" })
      .expect(201)
      .expect((res) => {
        expect(res.body).toHaveProperty("id");
        expect(res.body).toHaveProperty("username", "alice");
        // Never expose passwords or hashes in the response
        expect(res.body).not.toHaveProperty("password");
        expect(res.body).not.toHaveProperty("password_hash");
      });
  });

  test("returns 500 when the database is unavailable", () => {
    vi.mocked(query).mockRejectedValueOnce(new Error("DB connection failed"));

    return request(app)
      .post("/api/auth/register")
      .send({ username: "alice", password: "secure123" })
      .expect(500);
  });
});

describe("POST /api/auth/login", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test("returns 400 when password field is missing", () => {
    return request(app)
      .post("/api/auth/login")
      .send({ username: "alice" })
      .expect(400);
  });

  test("returns 401 when username does not exist", () => {
    vi.mocked(query).mockResolvedValueOnce({ rows: [] }); // no user found

    return request(app)
      .post("/api/auth/login")
      .send({ username: "nobody", password: "secure123" })
      .expect(401)
      .expect((res) => {
        // Use a generic message — don't tell the client whether it was
        // the username or the password that was wrong (security best practice)
        expect(res.body.message).toMatch(/invalid credentials/i);
      });
  });

  test("returns 401 when password is wrong", () => {
    vi.mocked(query).mockResolvedValueOnce({
      rows: [{ id: 1, username: "alice", password_hash: "$2b$10$hashed" }],
    });
    vi.mocked(bcrypt.compare).mockResolvedValueOnce(false);

    return request(app)
      .post("/api/auth/login")
      .send({ username: "alice", password: "wrongpassword" })
      .expect(401)
      .expect((res) => {
        expect(res.body.message).toMatch(/invalid credentials/i);
      });
  });

  test("returns 200 with user info and sets a session cookie on valid credentials", () => {
    vi.mocked(query).mockResolvedValueOnce({
      rows: [{ id: 1, username: "alice", password_hash: "$2b$10$hashed" }],
    });
    vi.mocked(bcrypt.compare).mockResolvedValueOnce(true);

    return request(app)
      .post("/api/auth/login")
      .send({ username: "alice", password: "secure123" })
      .expect(200)
      .expect((res) => {
        expect(res.headers["set-cookie"]).toBeDefined();
        expect(res.body).toHaveProperty("username", "alice");
        // The hash must never leave the server
        expect(res.body).not.toHaveProperty("password_hash");
      });
  });
});

