import { describe, test, expect, vi, beforeEach } from "vitest";
import request from "supertest";
import { app } from "../app.js";

vi.mock("../db.js", () => ({ query: vi.fn() }));

// The auth middleware is mocked so we can control authentication in each test
// without needing real sessions or tokens. We keep a reference to the inner
// function so we can swap its behavior per-test with mockImplementation.
const mockRequireAuth = vi.fn();
vi.mock("../middleware/auth.js", () => ({
  requireAuth: (req, res, next) => mockRequireAuth(req, res, next),
}));

import { query } from "../db.js";

// Helpers that configure the auth mock for the two common cases.
// Calling these at the top of a test makes its authentication state explicit.
const asUser = (user = { id: 1, username: "alice" }) => {
  mockRequireAuth.mockImplementation((req, res, next) => {
    req.user = user;
    next();
  });
};

const asGuest = () => {
  mockRequireAuth.mockImplementation((req, res) => {
    res.status(401).json({ message: "Unauthorized" });
  });
};

describe("GET /api/favorites", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test("returns 401 when not logged in", () => {
    asGuest();
    return request(app).get("/api/favorites").expect(401);
  });

  test("returns an empty array when user has no favorites", () => {
    asUser();
    vi.mocked(query).mockResolvedValueOnce({ rows: [] });

    return request(app)
      .get("/api/favorites")
      .expect(200)
      .expect((res) => {
        expect(res.body).toEqual([]);
      });
  });

  test("returns the user's saved favorites", () => {
    asUser();
    vi.mocked(query).mockResolvedValueOnce({
      rows: [
        { id: 1, entity_id: 20, entity_type: "anime", title: "Naruto" },
        { id: 2, entity_id: 1, entity_type: "manga", title: "One Piece" },
      ],
    });

    return request(app)
      .get("/api/favorites")
      .expect(200)
      .expect((res) => {
        expect(res.body).toHaveLength(2);
        expect(res.body[0]).toMatchObject({ entity_id: 20, entity_type: "anime" });
        expect(res.body[1]).toMatchObject({ entity_id: 1, entity_type: "manga" });
      });
  });
});

describe("POST /api/favorites", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test("returns 401 when not logged in", () => {
    asGuest();
    return request(app)
      .post("/api/favorites")
      .send({ entity_id: 20, entity_type: "anime", title: "Naruto" })
      .expect(401);
  });

  test("returns 400 when entity_type is not anime or manga", () => {
    asUser();
    return request(app)
      .post("/api/favorites")
      .send({ entity_id: 20, entity_type: "movie", title: "Some Movie" })
      .expect(400)
      .expect((res) => {
        expect(res.body.message).toMatch(/entity_type/i);
      });
  });

  test("returns 400 when entity_id is missing", () => {
    asUser();
    return request(app)
      .post("/api/favorites")
      .send({ entity_type: "anime", title: "Naruto" })
      .expect(400);
  });

  test("saves the favorite and returns 201 with the created row", () => {
    asUser();
    vi.mocked(query).mockResolvedValueOnce({
      rows: [{ id: 5, entity_id: 20, entity_type: "anime", title: "Naruto" }],
    });

    return request(app)
      .post("/api/favorites")
      .send({ entity_id: 20, entity_type: "anime", title: "Naruto" })
      .expect(201)
      .expect((res) => {
        expect(res.body).toMatchObject({ id: 5, entity_type: "anime", title: "Naruto" });
      });
  });
});

describe("DELETE /api/favorites/:id", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test("returns 401 when not logged in", () => {
    asGuest();
    return request(app).delete("/api/favorites/5").expect(401);
  });

  test("returns 404 when favorite does not exist or belongs to another user", () => {
    asUser();
    // The DELETE query uses WHERE id = $1 AND user_id = $2,
    // so it returns no rows when the favorite isn't found or isn't owned by this user.
    vi.mocked(query).mockResolvedValueOnce({ rows: [] });

    return request(app).delete("/api/favorites/999").expect(404);
  });

  test("deletes the favorite and returns 200", () => {
    asUser();
    vi.mocked(query).mockResolvedValueOnce({ rows: [{ id: 5 }] });

    return request(app).delete("/api/favorites/5").expect(200);
  });
});

