import { describe, test, expect } from "vitest";
import db from "../db.js";

// These tests exercise raw SQL against the PGlite instance created by setup.js.
// They verify that the schema is correct and that queries behave as expected —
// catching schema bugs (wrong column name, missing constraint) before the
// HTTP layer is involved.

describe("users table", () => {
  test("setup seeds a testuser row", () => {
    return db.sql`SELECT id, username FROM users WHERE username = 'testuser'`.then((rows) => {
      expect(rows).toHaveLength(1);
      expect(rows[0]).toHaveProperty("username", "testuser");
      // The hash must exist but must not be accidentally exposed
      expect(rows[0]).not.toHaveProperty("password_hash");
    });
  });

  test("inserts a new user and returns id and username", () => {
    return db.sql`
      INSERT INTO users (username, password_hash)
      VALUES ('alice', 'some_hash')
      RETURNING id, username
    `.then((rows) => {
      expect(rows[0]).toHaveProperty("username", "alice");
      expect(rows[0]).toHaveProperty("id");
    });
  });

  test("rejects a duplicate username", () => {
    return db.sql`INSERT INTO users (username, password_hash) VALUES ('testuser', 'hash')`
      .then(() => {
        throw new Error("should have rejected the duplicate");
      })
      .catch((err) => {
        expect(err.message).toMatch(/unique|duplicate/i);
      });
  });
});

describe("favorites table", () => {
  test("inserts a favorite for testuser and retrieves it", () => {
    return db.sql`SELECT id FROM users WHERE username = 'testuser'`
      .then((rows) => {
        const userId = rows[0].id;
        return db.sql`
          INSERT INTO favorites (user_id, entity_id, entity_type, title)
          VALUES (${userId}, 20, 'anime', 'Naruto')
          RETURNING *
        `;
      })
      .then((rows) => {
        expect(rows[0]).toMatchObject({
          entity_id: 20,
          entity_type: "anime",
          title: "Naruto",
        });
      });
  });

  test("selects only the favorites belonging to a given user", () => {
    return db.sql`SELECT id FROM users WHERE username = 'testuser'`
      .then((rows) => {
        const userId = rows[0].id;
        return db.sql`
          INSERT INTO favorites (user_id, entity_id, entity_type, title)
          VALUES (${userId}, 20, 'anime', 'Naruto'), (${userId}, 1, 'manga', 'One Piece')
        `.then(() => userId);
      })
      .then((userId) => {
        return db.sql`SELECT * FROM favorites WHERE user_id = ${userId}`;
      })
      .then((rows) => {
        expect(rows).toHaveLength(2);
      });
  });

  test("delete with user_id check does not remove another user's favorite", () => {
    // Insert a second user with a favorite
    return db.sql`INSERT INTO users (username, password_hash) VALUES ('bob', 'hash') RETURNING id`
      .then((rows) => {
        const bobId = rows[0].id;
        return db.sql`
          INSERT INTO favorites (user_id, entity_id, entity_type, title)
          VALUES (${bobId}, 1, 'manga', 'One Piece')
          RETURNING id
        `;
      })
      .then((rows) => {
        const favId = rows[0].id;
        // Attempt to delete bob's favorite using testuser's id
        return db.sql`SELECT id FROM users WHERE username = 'testuser'`.then((userRows) => {
          const testUserId = userRows[0].id;
          return db.sql`
            DELETE FROM favorites WHERE id = ${favId} AND user_id = ${testUserId}
            RETURNING id
          `;
        });
      })
      .then((deleted) => {
        // WHERE user_id = testuser's id won't match bob's row — returns nothing
        expect(deleted).toHaveLength(0);
      });
  });
});

